export const TextProps: S.Codec<TextProps> = S.lazy((): S.Codec<TextProps> => S.struct({style: S.option(TypographyStyle), color: S.option(ColorToken)}) as S.Codec<TextProps>);

export type Topic = Uint8Array;

export const Topic: S.Codec<Topic> = S.lazy((): S.Codec<Topic> => S.byteArray(32));

export interface TopicFilter {
  topics: Array<Topic | undefined>;
}

export const TopicFilter: S.Codec<TopicFilter> = S.lazy((): S.Codec<TopicFilter> => S.struct({topics: S.vec(S.option(Topic))}) as S.Codec<TopicFilter>);

export interface TxPayloadContextV1 {
  metadata: Hex;
  tokenSymbol: string;
  tokenDecimals: number;
  bestBlockHeight: number;
}

export const TxPayloadContextV1: S.Codec<TxPayloadContextV1> = S.lazy((): S.Codec<TxPayloadContextV1> => S.struct({metadata: Hex, tokenSymbol: S.str, tokenDecimals: S.u32, bestBlockHeight: S.u32}) as S.Codec<TxPayloadContextV1>);

export interface TxPayloadExtensionV1 {
  id: string;
  extra: Hex;
  additionalSigned: Hex;
}

export const TxPayloadExtensionV1: S.Codec<TxPayloadExtensionV1> = S.lazy((): S.Codec<TxPayloadExtensionV1> => S.struct({id: S.str, extra: Hex, additionalSigned: Hex}) as S.Codec<TxPayloadExtensionV1>);

export interface TxPayloadV1 {
  signer?: string;
  callData: Hex;
  extensions: Array<TxPayloadExtensionV1>;
  txExtVersion: number;
  context: TxPayloadContextV1;
}

export const TxPayloadV1: S.Codec<TxPayloadV1> = S.lazy((): S.Codec<TxPayloadV1> => S.struct({signer: S.option(S.str), callData: Hex, extensions: S.vec(TxPayloadExtensionV1), txExtVersion: S.u8, context: TxPayloadContextV1}) as S.Codec<TxPayloadV1>);

export type TypographyStyle =
  | { tag: "TitleXL"; value: undefined }
  | { tag: "Headline"; value: undefined }
  | { tag: "BodyM"; value: undefined }
  | { tag: "BodyS"; value: undefined }
  | { tag: "Caption"; value: undefined }
;

export const TypographyStyle: S.Codec<TypographyStyle> = S.lazy((): S.Codec<TypographyStyle> => S.taggedUnion({TitleXL: S.unit, Headline: S.unit, BodyM: S.unit, BodyS: S.unit, Caption: S.unit}));

export interface UserIdentity {
  dotNsIdentifier: DotNsIdentifier;
  publicKey: PublicKey;
}

export const UserIdentity: S.Codec<UserIdentity> = S.lazy((): S.Codec<UserIdentity> => S.struct({dotNsIdentifier: DotNsIdentifier, publicKey: PublicKey}) as S.Codec<UserIdentity>);

export type UserIdentityError =
  | { tag: "Rejected"; value: undefined }
  | { tag: "NotConnected"; value: undefined }
  | { tag: "Unknown"; value: { reason: string } }
;

export const UserIdentityError: S.Codec<UserIdentityError> = S.lazy((): S.Codec<UserIdentityError> => S.taggedUnion({Rejected: S.unit, NotConnected: S.unit, Unknown: S.struct({reason: S.str}) as S.Codec<{ reason: string }>}));

export type VersionedTxPayload =
  | { tag: "V1"; value: TxPayloadV1 }
;

export const VersionedTxPayload: S.Codec<VersionedTxPayload> = S.lazy((): S.Codec<VersionedTxPayload> => S.taggedUnion({V1: TxPayloadV1}));

export type VerticalAlignment =
  | { tag: "Top"; value: undefined }
  | { tag: "Center"; value: undefined }
  | { tag: "Bottom"; value: undefined }
;

export const VerticalAlignment: S.Codec<VerticalAlignment> = S.lazy((): S.Codec<VerticalAlignment> => S.taggedUnion({Top: S.unit, Center: S.unit, Bottom: S.unit}));

